export const TermAveragesList = ({ averages, isLoading }: Props) => {
  const [filterYear, setFilterYear] = useState("all")
  const [openYears, setOpenYears] = useState<Set<string>>(new Set())

  const years = useMemo(
    () =>
      averages
        ? [...new Set(averages.map((a) => a.yearStudy).filter(Boolean))]
            .sort()
            .reverse()
        : [],
    [averages]
  )

  const grouped = useMemo(() => {
    if (!averages) return {}
    const f =
      filterYear === "all"
        ? averages
        : averages.filter((a) => a.yearStudy === filterYear)
    const map: Record<string, TermAverage[]> = {}
    f.forEach((a) => {
      const y = a.yearStudy || "Khác"
      ;(map[y] ??= []).push(a)
    })
    return map
  }, [averages, filterYear])

  if (isLoading) {
    return (
      <div className="flex justify-center py-8">
        <Loader2 className="size-5 animate-spin text-muted-foreground" />
      </div>
    )
  }
  if (!averages?.length) {
    return (
      <div className="py-8 text-center text-sm text-muted-foreground">
        Chưa có dữ liệu điểm trung bình theo học kỳ
      </div>
    )
  }

  return (
    <ScrollArea className="max-h-[50vh] space-y-3 overflow-y-auto">
      <div className="space-y-3">
        <Select
          value={filterYear}
          onValueChange={(v) => setFilterYear(v ?? "all")}
        >
          <SelectTrigger className="w-44">
            <SelectValue>
              {filterYear === "all" ? "Tất cả năm học" : filterYear}
            </SelectValue>
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Tất cả năm học</SelectItem>
            {years.map((y) => (
              <SelectItem key={y} value={y}>
                {y}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {Object.keys(grouped).length === 0 ? (
          <div className="py-6 text-center text-sm text-muted-foreground">
            Không tìm thấy dữ liệu
          </div>
        ) : (
          Object.entries(grouped)
            .sort(([a], [b]) => b.localeCompare(a))
            .map(([year, items]) => {
              const toggleYear = () =>
                setOpenYears((prev) => {
                  const next = new Set(prev)
                  if (next.has(year)) {
                    next.delete(year)
                  } else {
                    next.add(year)
                  }
                  return next
                })
              return (
                <Collapsible
                  key={year}
                  open={openYears.has(year)}
                  onOpenChange={toggleYear}
                >
                  <CollapsibleTrigger
                    className={cn(
                      "flex w-full items-center gap-2 rounded-md px-3 py-1.5 text-sm",
                      openYears.has(year)
                        ? "bg-primary text-primary-foreground"
                        : "hover:bg-muted/80"
                    )}
                  >
                    {openYears.has(year) ? (
                      <ChevronDown className="size-3.5 shrink-0" />
                    ) : (
                      <ChevronRight className="size-3.5 shrink-0" />
                    )}
                    <span className="font-medium">Năm học {year}</span>
                    <Badge variant="secondary" className="ml-auto text-xs">
                      {items.length} học kỳ
                    </Badge>
                  </CollapsibleTrigger>
                  <CollapsibleContent className="px-1 pt-2">
                    <TermTable items={items} />
                  </CollapsibleContent>
                </Collapsible>
              )
            })
        )}
      </div>
    </ScrollArea>
  )
}

