import type { SerializedEditorState, SerializedLexicalNode } from "lexical";
import { normalizeAdminFilterValue, normalizeAdminFilterValues } from "@/lib";
import type {
  EditorParagraphNodeShape,
  EditorStateShape,
} from "./types";

export {
  slugify,
  formatDateTime,
  buildCategoryOptionTree,
  unwrapApiEnvelope as unwrapEnvelope,
  normalizePagedResult as normalizePaged,
  type CategoryTreeNode,
} from "@workspace/api-client";

export function createParagraphNode(text = ""): EditorParagraphNodeShape {
  return {
    children: text
      ? [
          {
            detail: 0,
            format: 0,
            mode: "normal",
            style: "",
            text,
            type: "text",
            version: 1,
          },
        ]
      : [],
    direction: null,
    format: "",
    indent: 0,
    textFormat: 0,
    textStyle: "",
    type: "paragraph",
    version: 1,
  };
}

export function createSerializedEditorState(
  paragraphs: EditorParagraphNodeShape[]
): SerializedEditorState {
  const state: EditorStateShape = {
    root: {
      children: paragraphs,
      direction: null,
      format: "",
      indent: 0,
      type: "root",
      version: 1,
    },
  };
  return state as SerializedEditorState;
}

export function getSeoStatus(
  length: number,
  recommendedMin: number,
  recommendedMax: number
) {
  if (length === 0) {
    return {
      label: "Chưa có nội dung",
      tone: "destructive" as const,
      hint: `Nên nhập khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  if (length < recommendedMin) {
    return {
      label: "Hơi ngắn",
      tone: "secondary" as const,
      hint: `Nên tăng lên khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  if (length > recommendedMax) {
    return {
      label: "Hơi dài",
      tone: "secondary" as const,
      hint: `Nên rút xuống khoảng ${recommendedMin}-${recommendedMax} ký tự.`,
    };
  }
  return {
    label: "Tốt cho SEO",
    tone: "default" as const,
    hint: `Độ dài đang nằm trong khoảng gợi ý ${recommendedMin}-${recommendedMax} ký tự.`,
  };
}

export function buildPostsFilterQuery(
  filters: { id: string; value: unknown }[]
): Record<string, string> {
  const query: Record<string, string> = {};
  for (const filter of filters) {
    if (filter.id === "published") {
      const values = normalizeAdminFilterValues(filter.value);
      if (values.length) query.published = values.join(",");
    } else if (filter.id === "categoryId") {
      const values = normalizeAdminFilterValues(filter.value);
      if (values.length) query.categoryId = values.join(",");
    } else if (filter.id === "tagId") {
      const values = normalizeAdminFilterValues(filter.value);
      if (values.length) query.tagId = values.join(",");
    } else if (filter.id === "updatedAt") {
      const v = normalizeAdminFilterValue(filter.value);
      if (v) query.updatedAt = v;
    }
  }
  return query;
}

export function isSerializedEditorState(
  value: unknown
): value is SerializedEditorState<SerializedLexicalNode> {
  return (
    typeof value === "object" &&
    value !== null &&
    "root" in value &&
    typeof (value as Record<string, unknown>).root === "object"
  );
}

export function fromLocalInputValue(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      return date.toISOString();
    }
  } catch {
    // Ignore
  }
  return value;
}

export function toLocalInputValue(value: string): string {
  if (!value) return "";
  try {
    const date = new Date(value);
    if (!isNaN(date.getTime())) {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, "0");
      const day = String(date.getDate()).padStart(2, "0");
      const hours = String(date.getHours()).padStart(2, "0");
      const minutes = String(date.getMinutes()).padStart(2, "0");
      return `${year}-${month}-${day}T${hours}:${minutes}`;
    }
  } catch {
    // Ignore
  }
  return value;
}

const EMPTY_EDITOR_PARAGRAPHS: EditorParagraphNodeShape[] = [createParagraphNode()];
const EMPTY_EDITOR_STATE = createSerializedEditorState(EMPTY_EDITOR_PARAGRAPHS);

function createEditorStateFromPlainText(raw: string): SerializedEditorState {
  const lines = raw
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line, index, arr) => line !== "" || index < arr.length - 1);
  const paragraphs =
    lines.length > 0 ? lines.map((line) => createParagraphNode(line)) : EMPTY_EDITOR_PARAGRAPHS;

  return createSerializedEditorState(paragraphs);
}

export function normalizeContentForEditor(value: unknown): SerializedEditorState {
  if (isSerializedEditorState(value)) return value;
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed.startsWith("{")) {
      try {
        const parsed = JSON.parse(trimmed) as unknown;
        if (isSerializedEditorState(parsed)) {
          return parsed;
        }
      } catch {
        // Fallback to plain text import below.
      }
    }

    const plainText =
      typeof window !== "undefined" && /<[^>]+>/.test(value)
        ? new DOMParser().parseFromString(value, "text/html").body.textContent ?? value
        : value;
    return createEditorStateFromPlainText(plainText);
  }
  return EMPTY_EDITOR_STATE;
}

src/app/posts/_component/_alert-dialog/p.content:
"use client";

import { Archive, ArchiveRestore, Trash2 } from "lucide-react";
import { AdminConfirmActionDialog } from "@/components/admin-confirm-action-dialog";
import type { PostConfirmAction } from "../types";

export interface PostsConfirmDialogProps {
  confirmAction: PostConfirmAction | null;
  deleteMutation: {
    isPending: boolean;
  };
  restoreMutation: {
    isPending: boolean;
  };
  purgeMutation: {
    isPending: boolean;
  };
  onOpenChange: (open: boolean) => void;
  onConfirm: () => void;
  contentClassName?: string;
}

export function PostsConfirmDialog({
  confirmAction,
  deleteMutation,
  restoreMutation,
  purgeMutation,
  onOpenChange,
  onConfirm,
  contentClassName,
}: PostsConfirmDialogProps) {
  if (!confirmAction) return null;

  const { kind, row } = confirmAction;

  return (
    <AdminConfirmActionDialog
      open={true}
      onOpenChange={onOpenChange}
      contentClassName={contentClassName}
      footerClassName="gap-2"
      icon={
        kind === "delete" ? (
          <Archive className="size-5 shrink-0 text-destructive" />
        ) : kind === "restore" ? (
          <ArchiveRestore className="size-5 shrink-0 text-primary" />
        ) : kind === "purge" ? (
          <Trash2 className="size-5 shrink-0 text-destructive" />
        ) : null
      }
      title={
        kind === "delete"
          ? "Đưa bài viết vào thùng rác?"
          : kind === "restore"
            ? "Khôi phục bài viết?"
            : kind === "purge"
              ? "Xóa vĩnh viễn bài viết?"
              : ""
      }
      description={
        kind === "delete"
          ? `«${row.title}» sẽ bị xóa tạm. Có thể khôi phục từ tab Thùng rác.`
          : kind === "restore"
            ? `Khôi phục «${row.title}» về danh sách đang hoạt động.`
            : kind === "purge"
              ? `«${row.title}» sẽ bị xóa khỏi cơ sở dữ liệu và không thể hoàn tác.`
              : null
      }
      confirmLabel={
        kind === "delete"
          ? "Xóa tạm"
          : kind === "restore"
            ? "Khôi phục"
            : kind === "purge"
              ? "Xóa vĩnh viễn"
              : "Xác nhận"
      }
      confirmDestructive={kind === "delete" || kind === "purge"}
      confirmDisabled={
        deleteMutation.isPending || restoreMutation.isPending || purgeMutation.isPending
      }
      confirmLoading={
        kind === "delete"
          ? deleteMutation.isPending
          : kind === "restore"
            ? restoreMutation.isPending
            : kind === "purge"
              ? purgeMutation.isPending
              : false
      }
      onConfirm={() => {
        void onConfirm();
      }}
    />
  );
}

src/app/posts/_component/_form/post-form.content:
"use client";

import { LexicalEditor } from "@thangph2146/lexical-editor";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@ui/components/card";
import { FieldError } from "@ui/components/field";
import { Input } from "@ui/components/input";
import { Label } from "@ui/components/label";
import { Switch } from "@ui/components/switch";
import { Textarea } from "@ui/components/textarea";
import { FormFieldCol, TreeMultiSelectInline } from "@ui/components/typing";
import { DatePicker } from "@ui/components/pickers";
import { TypographyH1 } from "@ui/components/typography";
import { cn } from "@ui/lib/utils";
import { ADMIN_PAGE_SUBTITLE_CLASS, ADMIN_PAGE_TITLE_PRIMARY_CLASS } from "@ui/lib/layout-shell";
import { Controller, type UseFormReturn } from "react-hook-form";
import { Sparkles, Search, CalendarClock, Tags, ArrowLeft, Globe, ImageIcon } from "lucide-react";
import { getSeoStatus, slugify as defaultSlugify } from "../utils";
import type { PostFormValues } from "../_hooks";
import type { CategoryTreeOption, TaxonomyOption } from "../types";

export interface PostFormShellProps {
  form: UseFormReturn<PostFormValues>;
  onSubmit: (values: PostFormValues) => Promise<void>;
  submitting: boolean;
  editingId: string | null;
  categoryTreeOptions: CategoryTreeOption[];
  tagsOptions: TaxonomyOption[];
  onBack: () => void;
  onReset: () => void;
}

export function PostFormShell({
  form,
  onSubmit,
  submitting,
  editingId,
  categoryTreeOptions,
  tagsOptions,
  onBack,
  onReset,
}: PostFormShellProps) {
  const { control, watch } = form;

  const watchedTitle = watch("title");
  const watchedSlug = watch("slug");
  const watchedExcerpt = watch("excerpt");
  const watchedImage = watch("image");

  const titleLength = watchedTitle.trim().length;
  const excerptLength = watchedExcerpt.trim().length;
  const normalizedSlug = watchedSlug.trim() || defaultSlugify(watchedTitle);
  const previewPath = normalizedSlug ? `/bai-viet/${normalizedSlug}` : "/bai-viet/ten-bai-viet";
  const titleSeo = getSeoStatus(titleLength, 30, 65);
  const excerptSeo = getSeoStatus(excerptLength, 70, 160);

  return (
    <>
      <div className="grid grid-cols-1 items-start gap-3 sm:grid-cols-[auto_1fr_auto]">
        <div className="flex flex-col gap-3">
          <Button
            type="button"
            variant="outline"
            className="w-fit"
            onClick={onBack}
          >
            <ArrowLeft className="size-4" />
            Quay lại
          </Button>
          <div>
            <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
              {editingId ? "Chỉnh sửa bài viết" : "Tạo bài viết mới"}
            </TypographyH1>
            <p className={ADMIN_PAGE_SUBTITLE_CLASS}>
              {editingId
                ? watchedTitle || "Đang tải..."
                : "Soạn nội dung, kiểm tra SEO và cấu hình xuất bản"}
            </p>
          </div>
        </div>
        <div className="flex justify-self-end gap-2">
          <Button
            type="button"
            variant="outline"
            onClick={onReset}
            disabled={submitting}
          >
            Đặt lại
          </Button>
          <Button
            type="submit"
            form="post-form"
            disabled={submitting}
          >
            {submitting ? "Đang lưu..." : editingId ? "Cập nhật" : "Xuất bản"}
          </Button>
        </div>
      </div>

      <form id="post-form" onSubmit={form.handleSubmit(onSubmit)}>
        <div className="grid gap-6 lg:grid-cols-3 my-6">
          <div className="space-y-6 lg:col-span-2">
            <Card className="border border-border/70 shadow-sm overflow-visible">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-lg">
                  <Sparkles className="size-5 text-primary" />
                  Biên tập nội dung
                </CardTitle>
                <CardDescription>
                  Soạn thảo nội dung chính cho bài viết.
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="max-w-6xl mx-auto">
                  <Controller
                    name="content"
                    control={control}
                    render={({ field }) => (
                      <LexicalEditor
                        value={field.value}
                        placeholder="Nhập nội dung bài viết..."
                        onChange={(value) => field.onChange(value)}
                        uploadsContext={undefined}
                        stickyTop={0}
                      />
                    )}
                  />
                </div>
              </CardContent>
            </Card>
          </div>

          <div className="space-y-6">
            <Card className="border border-border/70 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-lg">
                  <Search className="size-5 text-primary" />
                  Thông tin cơ bản
                </CardTitle>
                <CardDescription>
                  Tiêu đề, slug và mô tả ngắn — đây là những yếu tố ảnh hưởng trực tiếp tới SEO.
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <Controller
                  name="title"
                  control={control}
                  render={({ field, fieldState }) => (
                    <FormFieldCol label="Tiêu đề bài viết" required>
                      <Input
                        placeholder="VD: Thông báo tuyển sinh 2026"
                        {...field}
                        onChange={(e) => {
                          const { value } = e.target;
                          field.onChange(value);
                          if (!editingId) form.setValue("slug", defaultSlugify(value));
                        }}
                        className={cn(fieldState.error && "border-destructive")}
                      />
                      {fieldState.error && <FieldError>{fieldState.error.message}</FieldError>}
                      <div className="flex flex-wrap items-center justify-between gap-2 text-xs text-muted-foreground">
                        <span>Tiêu đề nên rõ chủ đề chính, dễ đọc và thu hút.</span>
                        <Badge variant={titleSeo.tone} className="mt-1">{titleLength} ký tự</Badge>
                      </div>
                    </FormFieldCol>
                  )}
                />

                <Controller
                  name="slug"
                  control={control}
                  render={({ field }) => (
                    <FormFieldCol label="Slug / đường dẫn">
                      <Input
                        placeholder="thong-bao-tuyen-sinh-2026"
                        {...field}
                        onChange={(e) => field.onChange(defaultSlugify(e.target.value))}
                      />
                      <div className="flex items-center gap-2 mt-1 text-xs text-muted-foreground">
                        <Globe className="size-3 shrink-0" />
                        <span className="break-all font-mono">{previewPath}</span>
                      </div>
                    </FormFieldCol>
                  )}
                />

                <Controller
                  name="excerpt"
                  control={control}
                  render={({ field }) => (
                    <FormFieldCol label="Mô tả ngắn gọn">
                      <Textarea
                        placeholder="Đoạn mô tả ngắn để hiển thị danh sách..."
                        {...field}
                      />
                      <div className="flex flex-wrap items-center justify-between gap-2 text-xs text-muted-foreground">
                        <span>Dùng làm mô tả tóm tắt và preview SEO.</span>
                        <Badge variant={excerptSeo.tone} className="mt-1">{excerptLength} ký tự</Badge>
                      </div>
                    </FormFieldCol>
                  )}
                />

                <div className="rounded-lg border border-dashed border-primary/30 bg-primary/5 p-3">
                  <p className="text-sm font-semibold text-foreground">Preview kết quả tìm kiếm</p>
                  <p className="mt-2 line-clamp-2 text-sm font-medium text-primary">
                    {watchedTitle.trim() || "Tiêu đề bài viết sẽ hiển thị tại đây"}
                  </p>
                  <p className="mt-1 break-all text-xs text-emerald-700 dark:text-emerald-400">
                    hub.local{previewPath}
                  </p>
                  <p className="mt-2 line-clamp-3 text-xs leading-5 text-muted-foreground">
                    {watchedExcerpt.trim() ||
                      "Mô tả ngắn của bài viết sẽ hiển thị ở đây để bạn kiểm tra cách trình bày SEO cơ bản."}
                  </p>
                </div>
              </CardContent>
            </Card>

            <Card className="border border-border/70 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-lg">
                  <CalendarClock className="size-5 text-primary" />
                  Xuất bản
                </CardTitle>
                <CardDescription>
                  Kiểm soát trạng thái hiển thị và thời điểm bài viết được phát hành.
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <Controller
                  name="published"
                  control={control}
                  render={({ field }) => (
                    <div className="flex items-center justify-between rounded-lg border border-outline-variant px-4 py-3">
                      <div>
                        <p className="text-sm font-semibold">Trạng thái hiển thị</p>
                        <p className="text-xs text-muted-foreground">
                          {field.value
                            ? "Bài viết đang ở chế độ xuất bản."
                            : "Bài viết đang là bản nháp, chưa hiển thị công khai."}
                        </p>
                      </div>
                      <Switch
                        checked={field.value}
                        onCheckedChange={(checked) => field.onChange(checked)}
                      />
                    </div>
                  )}
                />

                <Controller
                  name="publishedAt"
                  control={control}
                  render={({ field }) => (
                    <FormFieldCol label="Ngày xuất bản">
                      <DatePicker
                        value={field.value}
                        onChange={(v) => field.onChange(v ?? "")}
                        placeholder="Chọn ngày"
                      />
                    </FormFieldCol>
                  )}
                />
              </CardContent>
            </Card>

            <Card className="border border-border/70 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-lg">
                  <ImageIcon className="size-5 text-primary" />
                  Hình ảnh đại diện
                </CardTitle>
                <CardDescription>
                  Ảnh đại diện ảnh hưởng trực tiếp tới preview chia sẻ và cảm nhận trực quan.
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                <Controller
                  name="image"
                  control={control}
                  render={({ field }) => (
                    <FormFieldCol label="URL ảnh đại diện">
                      <Input placeholder="https://..." {...field} />
                    </FormFieldCol>
                  )}
                />
                {watchedImage.trim() ? (
                  <div className="overflow-hidden rounded-lg border border-border/70 bg-background">
                    <div className="flex items-center justify-between border-b border-border/70 px-3 py-2">
                      <p className="text-sm font-semibold text-foreground">Xem trước hình ảnh</p>
                      <span className="text-xs text-muted-foreground">Preview từ URL hiện tại</span>
                    </div>
                    <div className="bg-muted/20 p-3">
                      <img
                        src={watchedImage.trim()}
                        alt={watchedTitle.trim() || "Ảnh đại diện bài viết"}
                        className="max-h-100 w-full rounded-lg border border-border/60 object-contain bg-background"
                      />
                    </div>
                  </div>
                ) : null}
                <div className="rounded-lg border border-dashed border-border/70 bg-muted/20 p-3 text-sm text-muted-foreground">
                  {watchedImage.trim()
                    ? "Đã có URL ảnh đại diện. Kiểm tra lại tỉ lệ và nội dung ảnh trước khi xuất bản."
                    : "Chưa có ảnh đại diện. Nên bổ sung ảnh ngang rõ nội dung để preview bài viết tốt hơn."}
                </div>
              </CardContent>
            </Card>

            <Card className="sticky top-0 border border-border/70 shadow-sm">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-lg">
                  <Tags className="size-5 text-primary" />
                  Danh mục
