import { useCallback } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";

export const staffFormSchema = z.object({
  email: z.string().email("Email không hợp lệ"),
  fullName: z.string().min(1, "Họ tên không được để trống"),
  password: z.string().min(6, "Mật khẩu tối thiểu 6 ký tự").optional().or(z.literal("")),
  isActive: z.boolean(),
  roleCodes: z.array(z.string()).min(1, "Vui lòng chọn ít nhất một vai trò"),
  avatar: z.string().optional(),
});

export type StaffFormValues = z.infer<typeof staffFormSchema>;

interface UseStaffFormOptions {
  editingId?: string | null;
}

export function useStaffForm(options: UseStaffFormOptions = {}) {
  const { editingId } = options;

  const form = useForm<StaffFormValues>({
    resolver: zodResolver(staffFormSchema),
    defaultValues: {
      email: "",
      fullName: "",
      password: "",
      isActive: true,
      roleCodes: [],
      avatar: "",
    },
    mode: "onChange",
  });

  const resetForm = useCallback(() => {
    form.reset({
      email: "",
      fullName: "",
      password: "",
      isActive: true,
      roleCodes: [],
    });
  }, [form]);

  const populateForm = useCallback((user: {
    email: string;
    fullName: string;
    isActive: boolean;
    roles: { code: string }[];
    avatar?: string | null;
  }) => {
    form.reset({
      email: user.email,
      fullName: user.fullName,
      password: "",
      isActive: user.isActive,
      roleCodes: user.roles.map((r) => r.code),
      avatar: user.avatar ?? "",
    });
  }, [form]);

  const toggleRole = useCallback((code: string, checked: boolean) => {
    const currentRoles = form.getValues("roleCodes");
    if (checked) {
      form.setValue("roleCodes", [...new Set([...currentRoles, code])], { shouldDirty: true });
    } else {
      form.setValue("roleCodes", currentRoles.filter((c) => c !== code), { shouldDirty: true });
    }
  }, [form]);

  const getPayload = useCallback((): {
    email: string;
    fullName: string;
    password: string;
    isActive: boolean;
    roleCodes: string[];
    avatar?: string | null;
} => {
    const values = form.getValues();
    const payload: {
      email: string;
      fullName: string;
      password: string;
      isActive: boolean;
      roleCodes: string[];
      avatar?: string | null;
    } = {
      fullName: values.fullName.trim(),
      isActive: values.isActive,
      email: "",
      password: "",
      roleCodes: values.roleCodes,
      avatar: values.avatar?.trim() || null,
    };

    if (!editingId) {
      payload.email = values.email.trim();
      payload.password = values.password?.trim() || "";
    } else {
      payload.email = values.email.trim();
      const pw = values.password?.trim();
      payload.password = pw || "";
    }

    return payload;
  }, [form, editingId]);

  return {
    form,
    resetForm,
    populateForm,
    toggleRole,
    getPayload,
  };
}

src/app/staff/_component/_query/use-staf.content:
import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { CreateUserInput, StoreSyncSdk, UpdateUserInput } from "@workspace/api-client";
import { toast } from "sonner";
import { ApiError, api } from "@/lib/api";
import { queryKeys } from "@/hooks/queries";

type CreateStaffInput = Pick<
  CreateUserInput,
  "email" | "fullName" | "password" | "isActive" | "roleCodes"
>;

type UpdateStaffInput = Pick<
  UpdateUserInput,
  "fullName" | "password" | "isActive" | "roleCodes" | "avatar"
>;

export interface UseStaffMutationsProps {
  api: StoreSyncSdk;
}

export function useStaffMutations({ api: apiClient }: UseStaffMutationsProps) {
  const queryClient = useQueryClient();

  const createMutation = useMutation({
    mutationFn: async (input: CreateStaffInput) => {
      return apiClient.users.create({
        email: input.email,
        fullName: input.fullName,
        password: input.password,
        isActive: input.isActive,
        roleCodes: input.roleCodes,
      });
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
      ]);
      toast.success("Đã tạo tài khoản");
    },
    onError: (error) => {
      toast.error(error instanceof ApiError ? error.message : "Không tạo được user");
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, input }: { id: string; input: UpdateStaffInput }) => {
      return apiClient.users.update(id, {
        fullName: input.fullName,
        isActive: input.isActive,
        password: input.password,
        roleCodes: input.roleCodes,
        avatar: input.avatar,
      });
    },
    onSuccess: async (_data, variables) => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.staffProfile(variables.id) }),
      ]);
      toast.success("Đã cập nhật nhân sự");
    },
    onError: (error) => {
      toast.error(error instanceof ApiError ? error.message : "Không lưu được");
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => apiClient.users.remove(id),
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.usersTrashed() }),
      ]);
      toast.success("Đã đưa tài khoản vào thùng rác");
    },
    onError: (error) => {
      toast.error(error instanceof ApiError ? error.message : "Không xoá được");
    },
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) => apiClient.users.restore(id),
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.usersTrashed() }),
      ]);
      toast.success("Đã khôi phục tài khoản");
    },
    onError: (error) => {
      toast.error(error instanceof ApiError ? error.message : "Không khôi phục được");
    },
  });

  const purgeMutation = useMutation({
    mutationFn: async (id: string) => apiClient.users.purgeTrashed(id),
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.usersTrashed() }),
      ]);
      toast.success("Đã xóa vĩnh viễn tài khoản");
    },
    onError: (error) => {
      toast.error(error instanceof ApiError ? error.message : "Không xóa vĩnh viễn được");
    },
  });

  const bulkMutation = useMutation({
    mutationFn: async (input: {
      action: "delete" | "restore" | "hard-delete";
      ids: string[];
    }) => api.http.post("/admin/users/bulk", input),
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.staffUserList() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.usersTrashed() }),
      ]);
    },
  });

  return {
    createMutation,
    updateMutation,
    deleteMutation,
    restoreMutation,
    purgeMutation,
    bulkMutation,
  };
}

src/app/staff/_component/_table/staff-ta.content:
import type { ColumnFiltersState, OnChangeFn, RowSelectionState } from "@tanstack/react-table";
import { FilterX } from "lucide-react";
import { Button } from "@ui/components/button";
import { AdminDataTable } from "@/components/admin-data-table";
import { AdminTablePaginationFooter } from "@/components/admin-table-pagination-footer";
import { getStaffColumns } from "../columns";
import type { StaffRow } from "../types";

interface StaffTableProps {
  data: StaffRow[];
  isLoading: boolean;
  total: number;
  page: number;
  pageSize: number;
  onPageChange: (page: number) => void;
  onPageSizeChange: (pageSize: number) => void;
  columnFilters: ColumnFiltersState;
  onColumnFiltersChange: OnChangeFn<ColumnFiltersState>;
  globalFilter: string;
  onGlobalFilterChange: OnChangeFn<string>;
  selectedRowIds: RowSelectionState;
  onSelectedRowIdsChange: OnChangeFn<RowSelectionState>;
  onView: (user: StaffRow) => void;
  onEdit: (user: StaffRow) => void;
  onDelete: (user: StaffRow) => void;
  busy: boolean;
  currentUserId?: string;
  onBulkDelete: (ids: string[]) => void;
  onClearFilters: () => void;
  roleOptions?: { value: string; label: string }[];
}

export function StaffTable(props: StaffTableProps) {
  const {
    data,
    isLoading,
    total,
    page,
    pageSize,
    onPageChange,
    onPageSizeChange,
    columnFilters,
    onColumnFiltersChange,
    globalFilter,
    onGlobalFilterChange,
    selectedRowIds,
    onSelectedRowIdsChange,
    onView,
    onEdit,
    onDelete,
    busy,
    currentUserId,
    onBulkDelete,
    onClearFilters,
    roleOptions,
  } = props;

  const columns = getStaffColumns({ onView, onEdit, onDelete, busy, currentUserId, roleOptions });

  const paginationFooter = (
    <AdminTablePaginationFooter
      page={page}
      pageSize={pageSize}
      total={total}
      isLoading={isLoading}
      onPageChange={onPageChange}
      onPageSizeChange={onPageSizeChange}
      emptySummary="Không có nhân sự"
      itemLabel="tài khoản"
    />
  );

  return (
    <AdminDataTable<StaffRow>
      data={data}
      getRowId={(row) => String(row.id)}
      columns={columns}
      isLoading={isLoading}
      emptyLabel="Không có tài khoản khớp tìm kiếm API hoặc bộ lọc vai trò / cột."
      defaultExpandedAll={false}
      manualFiltering
      columnFilters={columnFilters}
      onColumnFiltersChange={onColumnFiltersChange}
      globalFilter={globalFilter}
      onGlobalFilterChange={onGlobalFilterChange}
      globalFilterPlaceholder="Tìm theo email, họ tên (API)…"
      rowSelectionEnabled
      selectedRowIds={selectedRowIds}
      onSelectedRowIdsChange={onSelectedRowIdsChange}
      canSelectRow={(row) => String(row.original.id) !== String(currentUserId ?? "")}
      bulkActions={[
        {
          id: "bulk-staff-delete",
          label: "Xóa tạm đã chọn",
          variant: "destructive",
          onAction: async (rows) => {
            const ids = rows
              .filter((u) => String(u.id) !== String(currentUserId ?? ""))
              .map((u) => String(u.id));
            if (!ids.length) return;
            await onBulkDelete(ids);
          },
        },
      ]}
      filterToolbarExtra={
        <div className="flex flex-wrap items-end gap-2">
          <Button
            type="button"
            variant="outline"
            onClick={onClearFilters}
          >
            <FilterX className="size-4" aria-hidden />
            Xóa bộ lọc
          </Button>
        </div>
      }
      csvExport={{ fileName: "nhan-su.csv" }}
      footer={paginationFooter}
    />
  );
}

