                        ) : (
                          <Eye className="h-4 w-4 text-muted-foreground" />
                        )}
                      </Button>
                    </div>
                  </Field>

                  <Field>
                    <Button
                      type="submit"
                      className="min-h-[44px] w-full bg-destructive px-8 text-destructive-foreground hover:bg-destructive/90"
                      disabled={busy}
                    >
                      <span className="text-base font-bold">
