import type { ProductUnitType } from "@workspace/api-client";
import { effectiveLineUnitPrice } from "@workspace/api-client";

/**
 * Giá hiển thị (`current`) và giá gạch (`list`) tại một số lượng dòng — khớp storefront.
 */
export function unitSellingAndListPrice(
  unit: ProductUnitType,
  quantity = 1,
): {
  current: number;
  list: number | null;
} {
  const { unitPrice, listUnitPrice, isSaleActive } = effectiveLineUnitPrice(
    unit,
    quantity,
  );
  return {
    current: unitPrice,
    list: isSaleActive && listUnitPrice > unitPrice ? listUnitPrice : null,
  };
}

src/providers/auth-provider.tsx.content:
"use client";

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import { useRouter } from "next/navigation";
import type { AuthUser } from "@workspace/api-client";
import { canAccessStaffAdmin } from "@workspace/api-client";
import {
  loginWithDevelopmentUser,
  loginWithEmail,
  loginWithGoogle,
  toAdminSessionUser,
} from "@/features/auth/auth-api";
import {
  ADMIN_SESSION_EVENT,
  ADMIN_SESSION_KEY,
  clearAdminSession,
  readAdminSession,
  writeAdminSession,
} from "@/lib/auth-session";
import { AUTH_LOGIN_PATH } from "@/lib/auth-routes";

function subscribe(callback: () => void) {
  if (typeof window === "undefined") return () => {};
  const onStorage = (e: StorageEvent) => {
    if (e.key === null || e.key === ADMIN_SESSION_KEY) callback();
  };
  const onCustom = () => callback();
  window.addEventListener("storage", onStorage);
  window.addEventListener(ADMIN_SESSION_EVENT, onCustom);
  return () => {
    window.removeEventListener("storage", onStorage);
    window.removeEventListener(ADMIN_SESSION_EVENT, onCustom);
  };
}

function getSessionSnapshot(): AuthUser | null {
  return readAdminSession();
}

function getServerSnapshot(): null {
  return null;
}

export type StaffLoginResult =
  | "success"
  | "invalid_credentials"
  | "staff_only";

type AuthContextValue = {
  user: AuthUser | null;
  login: (email: string, password: string) => Promise<StaffLoginResult>;
  loginDevelopment: (userId: string) => Promise<StaffLoginResult>;
  loginGoogle: (credential: string) => Promise<StaffLoginResult>;
  logout: () => void;
};

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const router = useRouter();
  const user = useSyncExternalStore(
    subscribe,
    getSessionSnapshot,
    getServerSnapshot,
  );

  const login = useCallback(async (email: string, password: string) => {
    let u: AuthUser;
    try {
      const payload = await loginWithEmail({
        email: email.trim(),
        password,
      });
      u = toAdminSessionUser(payload);
    } catch {
      return "invalid_credentials";
    }
    if (!canAccessStaffAdmin(u)) return "staff_only";
    writeAdminSession(u);
    window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
    return "success";
  }, []);

  const loginDevelopment = useCallback(async (userId: string) => {
    let u: AuthUser;
    try {
      const payload = await loginWithDevelopmentUser({
        userId: userId.trim(),
      });
      u = toAdminSessionUser(payload);
    } catch {
      return "invalid_credentials";
    }
    if (!canAccessStaffAdmin(u)) return "staff_only";
    writeAdminSession(u);
    window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
    return "success";
  }, []);

  const loginGoogle = useCallback(async (credential: string) => {
    let u: AuthUser;
    try {
      const payload = await loginWithGoogle(credential);
      u = toAdminSessionUser(payload);
    } catch {
      return "invalid_credentials";
    }
    if (!canAccessStaffAdmin(u)) return "staff_only";
    writeAdminSession(u);
    window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
    return "success";
  }, []);

  const logout = useCallback(() => {
    clearAdminSession();
    window.dispatchEvent(new Event(ADMIN_SESSION_EVENT));
    router.replace(AUTH_LOGIN_PATH);
  }, [router]);

  const value = useMemo(
    () => ({ user, login, loginDevelopment, loginGoogle, logout }),
    [user, login, loginDevelopment, loginGoogle, logout],
  );

  return (
    <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
  );
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error("useAuth phải dùng bên trong AuthProvider");
  }
  return ctx;
}

const noopSubscribe = () => () => {};

/** Tránh flash / hydration: server `false`, client `true` (không dùng setState trong effect). */
export function useClientReady(): boolean {
  return useSyncExternalStore(noopSubscribe, () => true, () => false);
}

